def min_delivery_distance(n, edges, charging_stations, max_range):
    import heapq

    if n == 1:
        return 0

    adj = [[] for _ in range(n)]
    for u, v, w in edges:
        adj[u].append((v, w))
        adj[v].append((u, w))

    charging_set = set(charging_stations)
    charging_set.add(0)
    charging_set.add(n - 1)

    # Build relay graph: for each charging station, find shortest distances
    # to other charging stations reachable within max_range
    relay_adj = {s: [] for s in charging_set}

    for src in charging_set:
        dist = [float('inf')] * n
        dist[src] = 0
        pq = [(0, src)]
        while pq:
            d, u = heapq.heappop(pq)
            if d > dist[u]:
                continue
            if d > max_range:
                break
            for v, w in adj[u]:
                nd = d + w
                if nd < dist[v] and nd <= max_range:
                    dist[v] = nd
                    heapq.heappush(pq, (nd, v))
        for station in charging_set:
            if station != src and dist[station] <= max_range:
                relay_adj[src].append((station, dist[station])))

    # Dijkstra on relay graph from 0 to n-1
    relay_dist = {s: float('inf') for s in charging_set}
    relay_dist[0] = 0
    pq = [(0, 0)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > relay_dist[u]:
            continue
        if u == n - 1:
            return d
        for v, w in relay_adj[u]:
            nd = d + w
            if nd < relay_dist[v]:
                relay_dist[v] = nd
                heapq.heappush(pq, (nd, v))

    return -1
